+    const createStyleProxy = (style: CSSStyleDeclaration) => {
+      return new Proxy(style, {
+        get(target, prop) {
+          // Usa target como receiver para evitar "Illegal invocation" em slots de objetos nativos no Chrome
+          const value = Reflect.get(target, prop, target);
+          
+          if (prop === 'getPropertyValue') {
+            return function (propertyName: string) {
+              const originalValue = target.getPropertyValue(propertyName);
+              if (typeof originalValue === 'string' && (originalValue.includes('oklch') || originalValue.includes('oklab'))) {
+                if (propertyName.includes('background')) return '#ffffff';
+                if (originalValue.includes('0.627') || originalValue.includes('0.53') || originalValue.includes('273')) {
+                  return '#7c3aed';
+                }
+                return '#0f172a';
+              }
+              return originalValue;
+            };
+          }
+          
+          if (typeof value === 'string' && (value.includes('oklch') || value.includes('oklab'))) {
+            const propStr = String(prop);
+            if (propStr === 'backgroundColor') return '#ffffff';
+            if (value.includes('0.627') || value.includes('0.53') || value.includes('273')) {
+              return '#7c3aed';
+            }
+            return '#0f172a';
+          }
+          
+          if (typeof value === 'function') {
+            return value.bind(target);
+          }
+          
+          return value;
+        }
+      });
+    };
+
+    window.getComputedStyle = function (elt, pseudoElt) {
+      // Garante a chamada no contexto window para evitar "Illegal invocation"
+      const style = originalGetComputedStyle.call(window, elt, pseudoElt);
+      return createStyleProxy(style);
+    };


